import React, {Component} from "react"; // vamos importar o React e também fazer um destructor em Component, para utilizar o componente somente referenciando Component

export default class Saudacao extends Component {
    setTipo(e) {
        this.props.tipo = e.target.value
    }

    render() {
        const a = this.props
        return (
            <div>
                <h1>{this.props.tipo} {this.props.nome}!</h1>
                <hr />
                <input type="text" placeholder="Tipo..."
                    value={this.props.tipo} onChange={e => this.setTipo(e)} />
                <input type="text" placeholder="Nome..." value={this.props.nome} />
            </div>
        )
    }
}
